/// resolved through [`contains`] in the fault path.
pub fn set_brk(nr: i32, new_break: u64) -> Result<u64, i32> {
    if new_break < HEAP_BASE {
        return Err(EINVAL);
    }
    let client = client_mut(nr).ok_or(EINVAL)?;
    let end = (new_break + PAGE_SIZE - 1) & !(PAGE_SIZE - 1);

