    for r in client.regions.iter_mut() {
        if r.kind == Kind::Heap {
            r.end = end;
            return Ok(end);
        }
    }
    // Otherwise claim a free slot for a fresh heap region.
    for r in client.regions.iter_mut() {
        if r.kind == Kind::Unused {
            *r = Region { start: HEAP_BASE, end, kind: Kind::Heap };
            return Ok(end);
        }
    }
    Err(EINVAL)
}

